def project_layers(act_arr, dir_arr):
    """act_arr[N,64,5120] · dir_arr[64,5120] → [N,64] (dot per layer)."""
    return np.einsum("nld,ld->nl", act_arr, dir_arr.astype(np.float32))


def all4_rate_of(rec):
    a4 = 0
    parsed = rec.get("parsed") or []
    for p in parsed:
        if p is not None and all(v == 4 for v in p.values()):
            a4 += 1
    return a4 / max(1, len(parsed))


def build_response_df(recs):
