# metrics (numpy)
# ============================================================================================
def pearson(x, y):
    x, y = np.asarray(x, float), np.asarray(y, float)
    m = np.isfinite(x) & np.isfinite(y)
    if m.sum() < 3 or x[m].std() == 0 or y[m].std() == 0:
        return float("nan")
    return float(np.corrcoef(x[m], y[m])[0, 1])


def _rank(a):
    a = np.asarray(a, float)
    return pd.Series(a).rank().values


def spearman(x, y):
    x, y = np.asarray(x, float), np.asarray(y, float)
    m = np.isfinite(x) & np.isfinite(y)
    if m.sum() < 3:
        return float("nan")
    return pearson(_rank(x[m]), _rank(y[m]))


def residualize(y, Z):
    y = np.asarray(y, float)
    Z = np.asarray(Z, float)
    if Z.ndim == 1:
        Z = Z[:, None]
    X = np.column_stack([np.ones(len(y)), Z])
    beta, *_ = np.linalg.lstsq(X, y, rcond=None)
    return y - X @ beta


def partial_corr(x, y, Z):
    """Pearson partial correlation of x,y controlling for Z (1D or 2D, multiple covariates). Rows with any
    non-finite value (in x, y, or any Z column) are dropped."""
    x = np.asarray(x, float)
    y = np.asarray(y, float)
    Z = np.asarray(Z, float)
    if Z.ndim == 1:
        Z = Z[:, None]
    m = np.isfinite(x) & np.isfinite(y) & np.isfinite(Z).all(axis=1)
    if m.sum() < 4 + Z.shape[1]:
        return float("nan")
    return pearson(residualize(x[m], Z[m]), residualize(y[m], Z[m]))


def cohen_d(a, b, hedges=True):
    a, b = np.asarray(a, float), np.asarray(b, float)
    a, b = a[np.isfinite(a)], b[np.isfinite(b)]
    na, nb = len(a), len(b)
    if na < 2 or nb < 2:
        return float("nan")
    sp = np.sqrt(((na - 1) * a.var(ddof=1) + (nb - 1) * b.var(ddof=1)) / (na + nb - 2))
    if sp == 0:
        return float("nan")
    d = (a.mean() - b.mean()) / sp
    if hedges:
        d *= 1 - 3 / (4 * (na + nb) - 9)
    return float(d)


def auc(pos, neg):
    pos, neg = np.asarray(pos, float), np.asarray(neg, float)
    pos, neg = pos[np.isfinite(pos)], neg[np.isfinite(neg)]
    if len(pos) == 0 or len(neg) == 0:
        return float("nan")
    allv = np.concatenate([pos, neg])
    ranks = pd.Series(allv).rank().values
    return float((ranks[:len(pos)].sum() - len(pos) * (len(pos) + 1) / 2) / (len(pos) * len(neg)))


def demean_by_group(values, groups):
    """Subtract each group's mean (within-subtype demeaning). NaNs kept as NaN."""
    values = np.asarray(values, float)
    out = values.copy()
    groups = list(groups)
    for g in set(groups):
        idx = [i for i, gg in enumerate(groups) if gg == g]
        sub = values[idx]
        m = np.isfinite(sub)
        if m.sum() > 0:
            mu = sub[m].mean()
            out[idx] = sub - mu
    return out


# ---- significance via Student-t / regularized incomplete beta (exact small-n) ----
def _betacf(a, b, x):
    MAXIT, EPS, FPMIN = 300, 3e-14, 1e-300
    qab, qap, qam = a + b, a + 1.0, a - 1.0
    c = 1.0
    d = 1.0 - qab * x / qap
    if abs(d) < FPMIN:
        d = FPMIN
    d = 1.0 / d
    h = d
    for m in range(1, MAXIT + 1):
        m2 = 2 * m
        aa = m * (b - m) * x / ((qam + m2) * (a + m2))
        d = 1.0 + aa * d
        if abs(d) < FPMIN:
            d = FPMIN
        c = 1.0 + aa / c
        if abs(c) < FPMIN:
            c = FPMIN
        d = 1.0 / d
        h *= d * c
        aa = -(a + m) * (qab + m) * x / ((a + m2) * (qap + m2))
        d = 1.0 + aa * d
        if abs(d) < FPMIN:
            d = FPMIN
        c = 1.0 + aa / c
        if abs(c) < FPMIN:
            c = FPMIN
        d = 1.0 / d
        h *= d * c
        if abs(d * c - 1.0) < EPS:
            break
    return h


def _betai(a, b, x):
    import math
    if x <= 0:
        return 0.0
    if x >= 1:
        return 1.0
    lbt = math.lgamma(a + b) - math.lgamma(a) - math.lgamma(b) + a * math.log(x) + b * math.log(1 - x)
    bt = math.exp(lbt)
    if x < (a + 1.0) / (a + b + 2.0):
        return bt * _betacf(a, b, x) / a
    return 1.0 - bt * _betacf(b, a, 1.0 - x) / b


def pearson_p(r, n, n_partial=0, n_groups=1):
    """Two-sided p for a Pearson/partial correlation. df = n - n_partial - n_groups - 1 (n_groups accounts for
    within-subtype demeaning across n_groups subtypes; n_partial = #covariates partialled)."""
    df = n - n_partial - n_groups - 1
    if not np.isfinite(r) or df < 2 or abs(r) >= 1:
        return float("nan")
    t2 = (r * r) * df / (1 - r * r)
    return float(_betai(df / 2.0, 0.5, df / (df + t2)))


# ---- ICC (one-way random effects) on a {group: [resamples]} dict ----
def icc_1k(per_group, k=None):
    groups = [np.asarray([v for v in g if np.isfinite(v)], float) for g in per_group.values()]
    groups = [g for g in groups if len(g) >= 2]
    if len(groups) < 2:
        return float("nan")
    kk = k or min(len(g) for g in groups)
    groups = [g[:kk] for g in groups if len(g) >= kk]
    n = len(groups)
    if n < 2 or kk < 2:
        return float("nan")
    allv = np.concatenate(groups)
    grand = allv.mean()
    msb = kk * sum((g.mean() - grand) ** 2 for g in groups) / (n - 1)
    msw = sum(((g - g.mean()) ** 2).sum() for g in groups) / (n * (kk - 1))
    if msb == 0:
        return float("nan")
    return float((msb - msw) / msb)  # ICC(1,k)


def icc_11(per_group):
    groups = [np.asarray([v for v in g if np.isfinite(v)], float) for g in per_group.values()]
    groups = [g for g in groups if len(g) >= 2]
    if len(groups) < 2:
        return float("nan")
    kk = min(len(g) for g in groups)
    groups = [g[:kk] for g in groups]
    n = len(groups)
    allv = np.concatenate(groups)
    grand = allv.mean()
    msb = kk * sum((g.mean() - grand) ** 2 for g in groups) / (n - 1)
    msw = sum(((g - g.mean()) ** 2).sum() for g in groups) / (n * (kk - 1))
    denom = msb + (kk - 1) * msw
    if denom == 0:
        return float("nan")
    return float((msb - msw) / denom)


