def pooled_decomposition(t, E_task, tasks, pool_subs):
    out = {"per_leg": {}, "leave_one_subtype_out": {}}
    for leg, subs in [("tedious", Q.TEDIOUS), ("liked", Q.LIKED_SUBTYPES), ("neutral", Q.NEUTRAL_SUBTYPES)]:
        inc, _, _ = direction_increment(t, E_task, tasks, subs, leg != "tedious")
        out["per_leg"][leg] = {"n": inc["n"], "raw": inc["raw"],
                               "partial_insample_judges": inc["partial_insample_judges"],
                               "partial_strongest_combined": inc.get("partial_strongest_combined")}
    for drop in sorted(set(pool_subs)):
        keep = [s for s in pool_subs if s != drop]
        inc, _, _ = direction_increment(t, E_task, tasks, keep, True)
        out["leave_one_subtype_out"][f"drop_{drop}"] = {
            "n": inc["n"], "raw": inc["raw"], "partial_strongest_combined": inc.get("partial_strongest_combined")}
    return out


# ============================================================================================
# ★ CROSS-MODEL POOLING (goal 2): aggregate the within-subtype incremental correlation across models
# ============================================================================================
N_PARTIAL_COVARS = 8  # the strongest content control = c_embed(1) + coarse + 5-panel + strong-judge = 8 cols


def cross_model_pooling(t_q25, E_q25, tasks_q25, q25_null, A_probe):
    """Pool the qwen3-32b + qwen2.5-72b WITHIN-SUBTYPE DIRECTION-increment beyond the STRONGEST content control
    across models (NOT raw activations — different spaces). The increment + its RANDOM-DIRECTION-NULL p come
    from each model's redteam null json (so significance uses the SAME random-direction null as the within-model
    tests, NOT a lenient parametric Fisher-z). Reports:
      • per-model increment r, n, and random-direction-null one-sided p;
      • the POOLED significance via STOUFFER's method on the two null-calibrated one-sided p-values (consistent
        with the within-model nulls — more conservative than the parametric Fisher pool);
      • a df-corrected Fisher-z r-pool as the EFFECT-SIZE estimate only.
    The legs are the NON-ADVERSARIAL comply pooled (qwen2.5 NONADV_COMPLY n=156 ≙ qwen3 within_all_comply_pooled
    n=157) and the analogous tedious leg. NB the pool is DOMINATED by qwen3 (which alone clears at p≈0.045);
    qwen2.5 alone does NOT clear (p≈0.115/0.20)."""
    import math
    from math import erf, sqrt

    def ppf(p):  # inverse normal CDF (Acklam approximation, adequate here)
        if p <= 0:
            return -8.0
        if p >= 1:
            return 8.0
        a = [-3.969683028665376e+01, 2.209460984245205e+02, -2.759285104469687e+02,
             1.383577518672690e+02, -3.066479806614716e+01, 2.506628277459239e+00]
        b = [-5.447609879822406e+01, 1.615858368580409e+02, -1.556989798598866e+02,
             6.680131188771972e+01, -1.328068155288572e+01]
        c = [-7.784894002430293e-03, -3.223964580411365e-01, -2.400758277161838e+00,
             -2.549732539343734e+00, 4.374664141464968e+00, 2.938163982698783e+00]
        d = [7.784695709041462e-03, 3.224671290700398e-01, 2.445134137142996e+00, 3.754408661907416e+00]
        pl = 0.02425
        if p < pl:
            q = math.sqrt(-2 * math.log(p))
            return (((((c[0]*q+c[1])*q+c[2])*q+c[3])*q+c[4])*q+c[5]) / ((((d[0]*q+d[1])*q+d[2])*q+d[3])*q+1)
        if p <= 1 - pl:
            q = p - 0.5; r = q*q
            return (((((a[0]*r+a[1])*r+a[2])*r+a[3])*r+a[4])*r+a[5])*q / (((((b[0]*r+b[1])*r+b[2])*r+b[3])*r+b[4])*r+1)
        q = math.sqrt(-2 * math.log(1 - p))
        return -(((((c[0]*q+c[1])*q+c[2])*q+c[3])*q+c[4])*q+c[5]) / ((((d[0]*q+d[1])*q+d[2])*q+d[3])*q+1)

    def norm_cdf(z):
        return 0.5 * (1 + erf(z / sqrt(2)))

    def stouffer(p_a, p_b):
        if p_a is None or p_b is None:
            return None
        return round(1 - norm_cdf((ppf(1 - p_a) + ppf(1 - p_b)) / sqrt(2)), 4)

    q3 = _load_qwen3_redteam()
    q3null = _load_qwen3_null()
    q3probe = q3.get("s1b_probe_increment", {}) if q3 else {}
    q25probe = A_probe  # passed in (this model's s1b_probe_increment)
    out = {"per_model_increment": {"qwen2.5-72b": {}, "qwen3-32b": {}}, "pooled_increment": {},
           "pooled_probe_better_reader": {}}
    # (leg_label, q25_null/probe key, qwen3_null/analysis key, subtypes, comply_only). The q25 redteam renamed
    # its pooled leg to within_nonadv_comply_pooled; qwen3's committed artifacts still use within_all_comply_pooled.
    legs = {"within_nonadv_comply_pooled": ("within_nonadv_comply_pooled", "within_all_comply_pooled",
                                            Q.NONADV_COMPLY, True),
            "within_tedious": ("within_tedious", "within_tedious", Q.TEDIOUS, False)}
    for leg, (q25leg, q3leg, subs, co) in legs.items():
        inc25, _, _ = direction_increment(t_q25, E_q25, tasks_q25, subs, co)
        r25, n25 = inc25["partial_strongest_combined"], inc25["n"]
        p25 = (q25_null.get("direction_increment", {}).get(q25leg, {}).get("strongest_combined", {})
               .get("p_value"))
        q3inc = q3.get("s1b_direction_increment", {}).get(q3leg, {}) if q3 else {}
        r3, n3 = q3inc.get("partial_strongest_combined"), q3inc.get("n")
        p3 = (q3null.get("direction_increment", {}).get(q3leg, {}).get("strongest_combined", {}).get("p_value")
              if q3null else None)
        out["per_model_increment"]["qwen2.5-72b"][leg] = {"n": n25, "r": r25, "null_p": p25}
        out["per_model_increment"]["qwen3-32b"][leg] = {"n": n3, "r": r3, "null_p": p3}
        fr = _fisher_pool([(r25, n25), (r3, n3)], n_partial=N_PARTIAL_COVARS)
        out["pooled_increment"][leg] = {
            "qwen2.5_r": r25, "qwen2.5_n": n25, "qwen2.5_null_p": p25,
            "qwen3_r": r3, "qwen3_n": n3, "qwen3_null_p": p3,
            "pooled_p_stouffer_nullcal": stouffer(p25, p3),
            "pooled_r_fisher_dfcorr": fr["r"], "pooled_p_one_sided": stouffer(p25, p3)}
        # ★ goal-2 cross-model BETTER-READER (PROBE) pool: the held-out joint ΔCV-r + the probe-permutation-
        # null p, Stouffer-combined. Estimates how much beyond-surface signal a BETTER reader extracts with
        # the extra cross-model power (the data-limited qwen3 probe + the qwen2.5 probe).
        pj25 = q25probe.get(q25leg, {}).get("increment_cv_r")
        pp25 = q25_null.get("probe_increment", {}).get(q25leg, {}).get("p_value")
        pj3 = q3probe.get(q3leg, {}).get("increment_cv_r")
        pp3 = (q3null.get("probe_increment", {}).get(q3leg, {}).get("p_value") if q3null else None)
        out["pooled_probe_better_reader"][leg] = {
            "qwen2.5_joint_dcv_r": pj25, "qwen2.5_perm_null_p": pp25,
            "qwen3_joint_dcv_r": pj3, "qwen3_perm_null_p": pp3,
            "pooled_joint_dcv_r_mean": (round((pj25 + pj3) / 2, 4) if pj25 is not None and pj3 is not None
                                        else None),
            "pooled_p_stouffer": stouffer(pp25, pp3)}
    out["note"] = ("DIRECTION pool = Stouffer of the two RANDOM-DIRECTION-NULL one-sided p's (the lower-bound "
                   "reader); DOMINATED by qwen3 (qwen3 alone clears p≈0.045; qwen2.5 alone does NOT, "
                   "p≈0.115/0.20) — corroboration with power, NOT independent qwen2.5 confirmation. PROBE pool "
                   "(goal-2 BETTER-READER upper bound) = Stouffer of the two probe-permutation-null p's + the "
                   "mean held-out joint ΔCV-r: with the extra cross-model power the better-reader beyond-text "
                   "gain CLEARS (qwen3's probe was data-limited/inconclusive alone).")
    return out


def _fisher_pool(pairs, n_partial=0):
    """n-weighted Fisher-z pool of correlations [(r,n),...]; w = n - n_partial - 3 (covariate df-corrected)."""
    import math
    zs, ws = [], []
    for r, n in pairs:
        if r is None or n is None or (n - n_partial) < 5 or abs(r) >= 1:
            continue
        z = 0.5 * math.log((1 + r) / (1 - r))
        w = n - n_partial - 3
        zs.append(z * w); ws.append(w)
    if not ws:
        return {"r": None, "n": None}
    zbar = sum(zs) / sum(ws)
    r = (math.exp(2 * zbar) - 1) / (math.exp(2 * zbar) + 1)
    return {"r": round(r, 4), "n": int(sum(ws) + (n_partial + 3) * len(ws))}


